-- ============================================================================
-- Dovetails Services LLC — Historical Job Backfill
-- ============================================================================
-- Loads real invoiced jobs and open estimates (from Google Drive documents)
-- into a dedicated "Dovetails Services LLC" account, separate from the
-- 002_seed_dev.sql Demo Account test fixtures.
--
-- Idempotent: every row uses a deterministic UUID + ON CONFLICT (id) DO NOTHING,
-- so re-running this file never creates duplicates.
--
-- Apply with:  psql "$DATABASE_URL" -v ON_ERROR_STOP=1 -f db/seeds/dovetails_historical_backfill.sql
-- (or via scripts/db-seed-dovetails.sh)
--
-- Estimate outcomes default to 'sent' for jobs not yet confirmed won/lost —
-- update these in the app once outcomes are known. Invoiced jobs reflect
-- as-billed totals and deposit/payment status from the source documents.
-- ============================================================================

BEGIN;

-- ----------------------------------------------------------------------------
-- 1. Account + owner user
-- ----------------------------------------------------------------------------
INSERT INTO accounts (id, name)
VALUES ('d0000000-0000-0000-0000-000000000001', 'Dovetails Services LLC')
ON CONFLICT (id) DO NOTHING;

-- Owner user. The password hash comes from the psql variable :owner_pw.
-- DEFAULT: a non-bcrypt sentinel that NO password can ever match, so the
-- account is login-DISABLED. Callers supply a real hash via
--   -v owner_pw='<bcrypt>'  to make the account loginable.
-- NOTE: the app has no self-service password-reset flow, so a login-disabled
-- owner is inaccessible until recovered. Always seed production with a real
-- password — use scripts/db-seed-dovetails.sh --prod with OWNER_PASSWORD set,
-- which hashes it for you. This keeps a guessable dev password out of prod
-- while still giving the production owner a working initial login.
\if :{?owner_pw}
\else
  \set owner_pw '!login-disabled-set-password-via-app'
\endif

INSERT INTO users (id, account_id, email, full_name, password_hash, role)
VALUES (
  'd0000000-0000-0000-0000-0000000000a1',
  'd0000000-0000-0000-0000-000000000001',
  'nick@mydovetails.com', 'Nick Garon',
  :'owner_pw', 'owner'
)
ON CONFLICT (id) DO NOTHING;

