-- Summary
DO $$
DECLARE
  c_count int; p_count int; j_count int; e_count int; i_count int; rev bigint;
BEGIN
  SELECT count(*) INTO c_count FROM clients   WHERE account_id = 'd0000000-0000-0000-0000-000000000001';
  SELECT count(*) INTO p_count FROM properties WHERE account_id = 'd0000000-0000-0000-0000-000000000001';
  SELECT count(*) INTO j_count FROM jobs       WHERE account_id = 'd0000000-0000-0000-0000-000000000001';
  SELECT count(*) INTO e_count FROM estimates  WHERE account_id = 'd0000000-0000-0000-0000-000000000001';
  SELECT count(*) INTO i_count FROM invoices   WHERE account_id = 'd0000000-0000-0000-0000-000000000001';
  SELECT COALESCE(sum(total_cents),0) INTO rev FROM invoices WHERE account_id = 'd0000000-0000-0000-0000-000000000001';
  RAISE NOTICE 'Dovetails backfill: % clients, % properties, % jobs, % estimates, % invoices, $% invoiced',
    c_count, p_count, j_count, e_count, i_count, (rev/100.0);
END $$;
